package com.wotb.web.admin;

import com.wotb.web.admin.dto.AdminDeleteUserResponse;
import com.wotb.web.admin.dto.AdminUserDetailDto;
import com.wotb.web.admin.dto.AdminUserDto;
import org.springframework.security.core.annotation.AuthenticationPrincipal;
import org.springframework.security.oauth2.jwt.Jwt;
import org.springframework.web.bind.annotation.DeleteMapping;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.PathVariable;
import org.springframework.web.bind.annotation.RequestMapping;
import org.springframework.web.bind.annotation.RequestParam;
import org.springframework.web.bind.annotation.RestController;

import java.util.List;

/** 管理员用户管理 API。需要 wotbtools-admin 角色。 */
@RestController
@RequestMapping("/api/admin/users")
public class AdminUserController {

    private final AdminUserService adminUserService;

    public AdminUserController(final AdminUserService adminUserService) {
        this.adminUserService = adminUserService;
    }

    @GetMapping
    public List<AdminUserDto> searchUsers(
            @RequestParam(required = false) final String query,
            @RequestParam(defaultValue = "50") final int limit) {
        return adminUserService.searchUsers(query, limit);
    }

    @GetMapping("/{keycloakUserId}")
    public AdminUserDetailDto getUser(@PathVariable final String keycloakUserId) {
        return adminUserService.getUser(keycloakUserId);
    }

    @DeleteMapping("/{keycloakUserId}")
    public AdminDeleteUserResponse deleteUser(
            @PathVariable final String keycloakUserId,
            @RequestParam(defaultValue = "false") final boolean confirm,
            @AuthenticationPrincipal final Jwt jwt) {
        return adminUserService.deleteUser(keycloakUserId, confirm, jwt);
    }
}

package com.wotb.web.admin;

import org.keycloak.admin.client.Keycloak;
import org.keycloak.representations.idm.UserRepresentation;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.stereotype.Service;

import java.util.List;

/** 通过 Keycloak Admin API 查询和删除 Keycloak 用户。 */
@Service
public class KeycloakAdminUserService {

    private final Keycloak keycloak;
    private final String realm;

    public KeycloakAdminUserService(final Keycloak keycloak,
                                    @Value("${keycloak.admin.realm}") final String realm) {
        this.keycloak = keycloak;
        this.realm = realm;
    }

    /** 查询 Keycloak 用户详情，用户不存在时返回 null。 */
    public UserRepresentation getUser(final String keycloakUserId) {
        try {
            return keycloak.realm(realm).users().get(keycloakUserId).toRepresentation();
        } catch (final jakarta.ws.rs.NotFoundException e) {
            return null;
        }
    }

    /** 获取 Keycloak 用户的联合身份（federated identities）。 */
    public List<org.keycloak.representations.idm.FederatedIdentityRepresentation> getFederatedIdentities(
            final String keycloakUserId) {
        try {
            return keycloak.realm(realm).users().get(keycloakUserId).getFederatedIdentity();
        } catch (final jakarta.ws.rs.NotFoundException e) {
            return List.of();
        }
    }

    /** 删除 Keycloak 用户。用户不存在时不抛异常。 */
    public void deleteUser(final String keycloakUserId) {
        try {
            keycloak.realm(realm).users().delete(keycloakUserId);
        } catch (final jakarta.ws.rs.NotFoundException e) {
            // 用户已在 Keycloak 侧被删除，视为成功
        }
    }
}

package com.wotb.web.admin;

import com.wotb.web.admin.dto.AdminDeleteUserResponse;
import org.springframework.http.HttpStatus;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.ExceptionHandler;
import org.springframework.web.bind.annotation.RestControllerAdvice;

/** 管理员 API 异常处理。 */
@RestControllerAdvice(basePackageClasses = AdminUserController.class)
public class AdminApiExceptionHandler {

    @ExceptionHandler(AdminBadRequestException.class)
    public ResponseEntity<AdminDeleteUserResponse> handleBadRequest(final AdminBadRequestException e) {
        final AdminDeleteUserResponse body = new AdminDeleteUserResponse(
                false, null, false, false, e.getErrorCode(), e.getMessage());
        return ResponseEntity.status(HttpStatus.BAD_REQUEST).body(body);
    }

    @ExceptionHandler(AdminConflictException.class)
    public ResponseEntity<AdminDeleteUserResponse> handleConflict(final AdminConflictException e) {
        final AdminDeleteUserResponse body = new AdminDeleteUserResponse(
                false, null, false, false, e.getErrorCode(), e.getMessage());
        return ResponseEntity.status(HttpStatus.CONFLICT).body(body);
    }

    @ExceptionHandler(AdminInternalException.class)
    public ResponseEntity<AdminDeleteUserResponse> handleInternal(final AdminInternalException e) {
        final AdminDeleteUserResponse body = new AdminDeleteUserResponse(
                false, null, false, false, e.getErrorCode(), e.getMessage());
        return ResponseEntity.status(HttpStatus.INTERNAL_SERVER_ERROR).body(body);
    }
}

